package server

import (
	"fmt"
	"sync"
	"time"

	pb "github.com/banking-platform/transaction/proto"
)

type InMemoryStore struct {
	mu              sync.RWMutex
	transactions    map[string]*pb.Transaction
	balances        map[string]*AccountBalance
	idempotencyKeys map[string]string // idempotency_key -> transaction_id
	accountTxns     map[string][]string // account_id -> []transaction_id
}

type AccountBalance struct {
	AvailableMinorUnits int64
	PendingMinorUnits   int64
	Currency            string
}

func NewInMemoryStore() *InMemoryStore {
	return &InMemoryStore{
		transactions:    make(map[string]*pb.Transaction),
		balances:        make(map[string]*AccountBalance),
		idempotencyKeys: make(map[string]string),
		accountTxns:     make(map[string][]string),
	}
}

func (s *InMemoryStore) GetBalance(accountID, currency string) (*AccountBalance, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	key := fmt.Sprintf("%s:%s", accountID, currency)
	bal, ok := s.balances[key]
	return bal, ok
}

func (s *InMemoryStore) EnsureAccount(accountID, currency string) {
	key := fmt.Sprintf("%s:%s", accountID, currency)
	if _, ok := s.balances[key]; !ok {
		s.balances[key] = &AccountBalance{
			AvailableMinorUnits: 0,
			PendingMinorUnits:   0,
			Currency:            currency,
		}
	}
}

func (s *InMemoryStore) CheckIdempotencyKey(key string) (string, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	txnID, ok := s.idempotencyKeys[key]
	return txnID, ok
}

func (s *InMemoryStore) GetTransaction(txnID string) (*pb.Transaction, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	txn, ok := s.transactions[txnID]
	return txn, ok
}

func (s *InMemoryStore) ProcessTransaction(txn *pb.Transaction) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	currency := txn.Amount.Currency
	now := time.Now().UTC().Format(time.RFC3339)

	switch txn.Type {
	case pb.TransactionType_TRANSACTION_TYPE_DEPOSIT:
		s.EnsureAccount(txn.DestinationAccountId, currency)
		destKey := fmt.Sprintf("%s:%s", txn.DestinationAccountId, currency)
		s.balances[destKey].AvailableMinorUnits += txn.Amount.AmountMinorUnits
		txn.Status = pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED

	case pb.TransactionType_TRANSACTION_TYPE_WITHDRAWAL:
		srcKey := fmt.Sprintf("%s:%s", txn.SourceAccountId, currency)
		s.EnsureAccount(txn.SourceAccountId, currency)
		if s.balances[srcKey].AvailableMinorUnits < txn.Amount.AmountMinorUnits {
			txn.Status = pb.TransactionStatus_TRANSACTION_STATUS_FAILED
			txn.UpdatedAt = now
			s.transactions[txn.TransactionId] = txn
			return fmt.Errorf("insufficient funds: available %d, requested %d",
				s.balances[srcKey].AvailableMinorUnits, txn.Amount.AmountMinorUnits)
		}
		s.balances[srcKey].AvailableMinorUnits -= txn.Amount.AmountMinorUnits
		txn.Status = pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED

	case pb.TransactionType_TRANSACTION_TYPE_TRANSFER:
		srcKey := fmt.Sprintf("%s:%s", txn.SourceAccountId, currency)
		destKey := fmt.Sprintf("%s:%s", txn.DestinationAccountId, currency)
		s.EnsureAccount(txn.SourceAccountId, currency)
		s.EnsureAccount(txn.DestinationAccountId, currency)
		if s.balances[srcKey].AvailableMinorUnits < txn.Amount.AmountMinorUnits {
			txn.Status = pb.TransactionStatus_TRANSACTION_STATUS_FAILED
			txn.UpdatedAt = now
			s.transactions[txn.TransactionId] = txn
			return fmt.Errorf("insufficient funds: available %d, requested %d",
				s.balances[srcKey].AvailableMinorUnits, txn.Amount.AmountMinorUnits)
		}
		s.balances[srcKey].AvailableMinorUnits -= txn.Amount.AmountMinorUnits
		s.balances[destKey].AvailableMinorUnits += txn.Amount.AmountMinorUnits
		txn.Status = pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED

	default:
		return fmt.Errorf("unsupported transaction type: %v", txn.Type)
	}

	txn.UpdatedAt = now
	s.transactions[txn.TransactionId] = txn

	if txn.IdempotencyKey != "" {
		s.idempotencyKeys[txn.IdempotencyKey] = txn.TransactionId
	}

	if txn.SourceAccountId != "" {
		s.accountTxns[txn.SourceAccountId] = append(s.accountTxns[txn.SourceAccountId], txn.TransactionId)
	}
	if txn.DestinationAccountId != "" && txn.DestinationAccountId != txn.SourceAccountId {
		s.accountTxns[txn.DestinationAccountId] = append(s.accountTxns[txn.DestinationAccountId], txn.TransactionId)
	}

	return nil
}

func (s *InMemoryStore) ListTransactions(accountID string, pageSize int, pageToken string) ([]*pb.Transaction, string, int) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	txnIDs, ok := s.accountTxns[accountID]
	if !ok {
		return nil, "", 0
	}

	totalCount := len(txnIDs)

	startIdx := 0
	if pageToken != "" {
		for i, id := range txnIDs {
			if id == pageToken {
				startIdx = i + 1
				break
			}
		}
	}

	if pageSize <= 0 {
		pageSize = 50
	}

	endIdx := startIdx + pageSize
	if endIdx > len(txnIDs) {
		endIdx = len(txnIDs)
	}

	var result []*pb.Transaction
	for _, id := range txnIDs[startIdx:endIdx] {
		if txn, exists := s.transactions[id]; exists {
			result = append(result, txn)
		}
	}

	nextPageToken := ""
	if endIdx < len(txnIDs) {
		nextPageToken = txnIDs[endIdx-1]
	}

	return result, nextPageToken, totalCount
}